def mock_get(url, status=200, body=None):
    return {"url": url, "status": status, "body": body or {}}
print(mock_get("https://api.example/entities/1", 200, {"id": "E1"}))

def parse_entity(payload):
    if "id" not in payload or "region" not in payload:
        raise ValueError("missing id/region")
    return {"id": payload["id"], "region": payload["region"]}
print(parse_entity({"id": "E1", "region": "Lima", "extra": 1}))

STATUS_ACTION = {200: "use_body", 404: "missing", 429: "retry", 500: "retry", 400: "fix_client"}
for s in [200, 404, 429, 500, 400]:
    print(s, STATUS_ACTION[s])

def call_with_timeout(fn, timeout_s=1.0):
    # simulación: si fn lanza TimeoutError, propaga
    return fn()
def flaky():
    raise TimeoutError("timeout")
try:
    call_with_timeout(flaky)
except TimeoutError:
    print("TimeoutError handled → candidate for backoff retry")

def collect_pages(pages):
    out = []
    for p in pages:
        out.extend(p)
    return out
print(collect_pages([[1, 2], [3], []]))

def should_retry(status, attempt, max_attempts=3):
    if attempt >= max_attempts:
        return False
    return status in (429, 500, 502, 503)
for st, a in [(429, 1), (400, 1), (500, 3)]:
    print(st, a, should_retry(st, a))

cache = {}
def cached_get(key, loader):
    if key not in cache:
        cache[key] = loader()
    return cache[key]
print(cached_get("E1", lambda: {"id": "E1"}))
print(cached_get("E1", lambda: {"id": "OTHER"}))

def min_provenance(url, status, cache_hit):
    return {
        "source_url": url,
        "fetched_at": "2026-07-20T00:00:00Z",
        "status_code": status,
        "cache_hit": cache_hit,
    }
print(min_provenance("https://api.example/x", 200, False))

def fetch_with_fallback(status, local_body):
    if status >= 500:
        return (local_body, "offline")
    if status == 200:
        return ({"online": True}, "online")
    return (local_body, "offline")
print(fetch_with_fallback(500, {"local": 1}))
print(fetch_with_fallback(200, {"local": 1}))

matrix = {
    (400, "no_retry"): "fix_client",
    (429, "retry"): "backoff",
    (500, "retry"): "backoff",
    (200, "use"): "use_body",
}
for k, v in matrix.items():
    print(k, "→", v)

import sqlite3
con = sqlite3.connect(":memory:")
con.executescript("""
CREATE TABLE entities(id TEXT PRIMARY KEY, name TEXT);
CREATE TABLE evidence(id TEXT PRIMARY KEY, entity_id TEXT, kind TEXT);
INSERT INTO entities VALUES ('C001','Ana');
INSERT INTO evidence VALUES ('E1','C001','geo');
""")
rows = con.execute(
    "SELECT e.name, v.kind FROM entities e JOIN evidence v ON e.id=v.entity_id"
).fetchall()
print(rows)
con.close()

def normalize_address(raw: str) -> str:
    return " ".join(raw.strip().upper().split())
print(normalize_address("  jr. unión  450 "))

# geocode mock: solo campos permitidos
def geocode_payload(street: str, city: str):
    return {"street": street, "city": city}
print(geocode_payload("JR UNION 450", "LIMA"))

FORBIDDEN = {"document_id", "api_token", "password", "full_name"}
def allowed_for_public_geocoder(payload: dict) -> bool:
    return not any(k in FORBIDDEN for k in payload)
print(allowed_for_public_geocoder({"street": "X", "city": "Lima"}))
print(allowed_for_public_geocoder({"street": "X", "document_id": "123"}))

def as_relationship_signal(km: float, threshold_km: float = 2.0) -> dict:
    return {
        "geo_distance_km": km,
        "signal": km <= threshold_km,
        "note": "geoseñal de relación, no veredicto de parentesco/fraude",
    }
print(as_relationship_signal(1.2))
